package com.user.nn.models.cv;

import com.user.nn.core.*;
import com.user.nn.core.Module;
import com.user.nn.containers.*;
import com.user.nn.layers.*;
import com.user.nn.activations.*;
import com.user.nn.norm.*;
import com.user.nn.pooling.*;

/**
 * ResNet architecture implementation.
 * Supports ResNet-18, ResNet-34, etc.
 * Optimized for CIFAR-10 (32x32 input).
 */
public class ResNet extends Module {
    
    public static class BasicBlock extends Module {
        public Sequential layers;
        public Module downsample;
        public int stride;

        public BasicBlock(int inChannels, int outChannels, int inH, int inW, int stride) {
            this.stride = stride;
            this.layers = new Sequential();
            
            // First conv
            layers.add(new Conv2d(inChannels, outChannels, 3, 3, inH, inW, stride, 1, false));
            layers.add(new BatchNorm2d(outChannels));
            layers.add(new ReLU());
            
            int midH = (inH + 2 * 1 - 3) / stride + 1;
            int midW = (inW + 2 * 1 - 3) / stride + 1;

            // Second conv
            layers.add(new Conv2d(outChannels, outChannels, 3, 3, midH, midW, 1, 1, false));
            layers.add(new BatchNorm2d(outChannels));
            
            addModule("layers", layers);

            if (stride != 1 || inChannels != outChannels) {
                Sequential ds = new Sequential();
                ds.add(new Conv2d(inChannels, outChannels, 1, 1, inH, inW, stride, 0, false));
                ds.add(new BatchNorm2d(outChannels));
                this.downsample = ds;
                addModule("downsample", downsample);
            } else {
                this.downsample = null;
            }
        }

        @Override
        public Tensor forward(Tensor x) {
            Tensor identity = x;
            if (downsample != null) {
                identity = downsample.forward(x);
            }
            Tensor out = layers.forward(x);
            out = Torch.add(out, identity);
            return Torch.relu(out);
        }
    }

    public Sequential initial;
    public Sequential layer1;
    public Sequential layer2;
    public Sequential layer3;
    public Sequential layer4;
    public Linear fc;

    public ResNet(int[] numBlocks, int numClasses, int inH, int inW) {
        // Initial layers for CIFAR-10 (small input)
        this.initial = new Sequential();
        initial.add(new Conv2d(3, 64, 3, 3, inH, inW, 1, 1, false));
        initial.add(new BatchNorm2d(64));
        initial.add(new ReLU());
        addModule("initial", initial);

        int curH = inH;
        int curW = inW;
        int curC = 64;

        this.layer1 = makeLayer(curC, 64, numBlocks[0], curH, curW, 1);
        addModule("layer1", layer1);
        curC = 64;

        this.layer2 = makeLayer(curC, 128, numBlocks[1], curH, curW, 2);
        addModule("layer2", layer2);
        curC = 128;
        curH /= 2; curW /= 2;

        this.layer3 = makeLayer(curC, 256, numBlocks[2], curH, curW, 2);
        addModule("layer3", layer3);
        curC = 256;
        curH /= 2; curW /= 2;

        this.layer4 = makeLayer(curC, 512, numBlocks[3], curH, curW, 2);
        addModule("layer4", layer4);
        curC = 512;
        curH /= 2; curW /= 2;

        this.fc = new Linear(512, numClasses, true);
        addModule("fc", fc);
    }

    private Sequential makeLayer(int inChannels, int outChannels, int blocks, int inH, int inW, int stride) {
        Sequential seq = new Sequential();
        seq.add(new BasicBlock(inChannels, outChannels, inH, inW, stride));
        
        int curH = (inH + 2 * 1 - 3) / stride + 1;
        int curW = (inW + 2 * 1 - 3) / stride + 1;

        for (int i = 1; i < blocks; i++) {
            seq.add(new BasicBlock(outChannels, outChannels, curH, curW, 1));
        }
        return seq;
    }

    @Override
    public Tensor forward(Tensor x) {
        Tensor out = initial.forward(x);
        out = layer1.forward(out);
        out = layer2.forward(out);
        out = layer3.forward(out);
        out = layer4.forward(out);
        
        // Global Average Pooling
        out = Functional.adaptive_avg_pool2d(out, 1, 1);
        out = out.view(out.shape[0], -1);
        out = fc.forward(out);
        return out;
    }

    public static ResNet resnet18(int numClasses, int inH, int inW) {
        return new ResNet(new int[]{2, 2, 2, 2}, numClasses, inH, inW);
    }

    public static ResNet resnet34(int numClasses, int inH, int inW) {
        return new ResNet(new int[]{3, 4, 6, 3}, numClasses, inH, inW);
    }
}
